# Facts as Python facts (database)
facts = [
    ('father', 'john', 'mary'),
    ('father', 'john', 'tom'),
    ('mother', 'susan', 'mary'),
    ('mother', 'susan', 'tom'),
]

# Rules as Python functions
def parent(x, y):
    return father(x, y) or mother(x, y)

def father(x, y):
    return ('father', x, y) in facts

def mother(x, y):
    return ('mother', x, y) in facts

def sibling(x, y):
    if x == y:
        return False
    # Find common parent
    for z in range(len(facts)):
        if parent(z, x) and parent(z, y):
            return True
    return False

# Query equivalent
# parent('john', who) would return ['mary', 'tom']

#include <stdio.h>
#include <stdbool.h>

// Prolog's member in C - imperative approach
bool member(int element, int list[], int length) {
    for (int i = 0; i < length; i++) {
        if (list[i] == element) {
            return true;  // Found, return immediately
        }
    }
    return false;  // Not found
}

// If we wanted ALL solutions (like Prolog backtracking),
// we'd need a different approach with callbacks
void member_all(int element, int list[], int length) {
    printf("Solutions: ");
    for (int i = 0; i < length; i++) {
        if (list[i] == element) {
            printf("Index %d ", i);  // Show each occurrence
        }
    }
    printf("\n");
}

int main() {
    int list[] = {1, 2, 3, 2, 4};

    // Single solution (like Prolog's first answer)
    printf("member(2): %s\n", member(2, list, 5) ? "true" : "false");

    // All solutions (Prolog backtracking)
    member_all(2, list, 5);  // Shows indices 1 and 3

    return 0;
}
